int32_t SystemAPB1_Clock_Speed(void)
{
	return (SystemCoreClock >> APBPrescTable[(RCC->CFGR & RCC_CFGR_PPRE1) >> RCC_CFGR_PPRE1_Pos]);
}

int32_t SystemAPB2_Clock_Speed(void)
{
	return (SystemCoreClock >> APBPrescTable[(RCC->CFGR & RCC_CFGR_PPRE2) >> RCC_CFGR_PPRE2_Pos]);
}

void MCU_Clock_Setup(void)
{
	SystemInit();
	// Clock is derived from HSE_VALUE, so PLL_N adapts to the external crystal.
	uint8_t pll_m = (uint8_t)MCU_PLL_M_VALUE;
	uint8_t pll_n = (uint8_t)MCU_PLL_N_VALUE;
	uint8_t pll_p = 0; // 0x00: PLLP = 2, 0x01: PLLP = 4, 0x02: PLLP = 6, 0x03: PLLP = 8
	uint8_t pll_q = 4; // Used for USB, SDIO, RNG (48MHz), Using ClockCoreSystem 96MHz

	RCC->PLLCFGR = 0x00000000;

	RCC->CR |= RCC_CR_HSEON;
	while (!(RCC->CR & RCC_CR_HSERDY)) {}
	RCC->APB1ENR |= RCC_APB1ENR_PWREN;
	PWR->CR |= PWR_CR_VOS;
	FLASH->ACR |= FLASH_ACR_ICEN | FLASH_ACR_PRFTEN | FLASH_ACR_DCEN | FLASH_ACR_LATENCY_3WS;
	RCC->PLLCFGR |= (pll_q << 24) | (pll_p << 16) | (pll_n << 6) | (pll_m << 0);
	RCC->PLLCFGR |= 1 << 22;
	//  RCC->PLLCFGR = 0x4403019;
	RCC->CFGR |= RCC_CFGR_HPRE_DIV1;
	RCC->CFGR |= RCC_CFGR_PPRE1_DIV2;
	RCC->CFGR |= RCC_CFGR_PPRE2_DIV1;
	//	RCC-> APB2ENR |= 0x4000;
	RCC->CR |= RCC_CR_PLLON;
	while (!(RCC->CR & RCC_CR_PLLRDY)) {}
	//	RCC -> CR |= RCC_CR_PLLI2SON;
	//	while(!(RCC->CR & RCC_CR_PLLI2SRDY)){}
	RCC->CFGR |= RCC_CFGR_SW_PLL;
	while ((RCC->CFGR & RCC_CFGR_SWS_PLL) != RCC_CFGR_SWS_PLL)
		;
	SystemCoreClockUpdate();
	// SysTick_Config(SystemCoreClock/1000);
	APB1CLK_SPEED = SystemAPB1_Clock_Speed();
	APB2CLK_SPEED = SystemAPB2_Clock_Speed();
	RCC->APB2ENR |= RCC_APB2ENR_SYSCFGEN;
}

static void OLED_ShowLines(const char *line1, const char *line2, const char *line3)
{
	char display_line1[MAX_OLED_CHARS + 1];
	char display_line2[MAX_OLED_CHARS + 1];
	char display_line3[MAX_OLED_CHARS + 1];

	snprintf(display_line1, sizeof(display_line1), "%s", line1);
	snprintf(display_line2, sizeof(display_line2), "%s", line2);
	snprintf(display_line3, sizeof(display_line3), "%s", line3);

	SH1106_Fill(SH1106_COLOR_BLACK);
	SH1106_GotoXY(0, 0);
	SH1106_Puts(display_line1, &Font_7x10, SH1106_COLOR_WHITE);
	SH1106_GotoXY(0, 16);
	SH1106_Puts(display_line2, &Font_7x10, SH1106_COLOR_WHITE);
	SH1106_GotoXY(0, 32);
	SH1106_Puts(display_line3, &Font_7x10, SH1106_COLOR_WHITE);
	SH1106_UpdateScreen();
}
